// Helper function to get tools by category
export const getToolsByCategory = (category: string) => {
  if (category === "All") return allIndianTools;
  return allIndianTools.filter(tool => tool.category === category);
};

// Helper function to search tools
export const searchTools = (searchTerm: string) => {
  const term = searchTerm.toLowerCase();
  return allIndianTools.filter(tool => 
    tool.title.toLowerCase().includes(term) ||
    tool.desc.toLowerCase().includes(term) ||
    tool.tags.some(tag => tag.toLowerCase().includes(term))
  );
};

